#include <stdio.h>
#include <stdint.h>
int main() {
    int Q, S1, A, B;
    scanf("%d %d %d %d", &Q, &S1, &A, &B);
    uint32_t set[Q];
    int size = 0;
    for (int i = 0; i < Q; i++) {
        if (S1 % 2 == 1) {
            int num = S1 / 2;
            int found = 0;
            for (int j = 0; j < size; j++) {
                if (set[j] == num) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                set[size++] = num;
            }
        } else {
            int num = S1 / 2;
            for (int j = 0; j < size; j++) {
                if (set[j] == num) {
                    for (int k = j; k < size - 1; k++) {
                        set[k] = set[k + 1];
                    }
                    size--;
                    break;
                }
            }
        }
        S1 = (uint32_t)((uint64_t)A * S1 + B) % (1ULL << 32);
    }
    uint64_t sum = 0;
    for (int i = 0; i < size; i++) {
        sum += set[i];
    }
    printf("%llu\n", sum);
    return 0;
}

